package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Constructor;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testFormat_withNormalValues() throws IOException {
        String result = csvFormat.format("a", "b", "c");
        // Expected output: a,b,c (trimmed)
        assertEquals("a,b,c", result);
    }

    @Test
    void testFormat_withNullValue() throws IOException {
        String result = csvFormat.format("a", null, "c");
        // null should be printed as empty string unless nullString is set
        assertEquals("a,,c", result);
    }

    @Test
    void testFormat_withEmptyValues() throws IOException {
        String result = csvFormat.format("", "", "");
        assertEquals(",,", result);
    }

    @Test
    void testFormat_withNoValues() throws IOException {
        String result = csvFormat.format();
        assertEquals("", result);
    }

    @Test
    void testFormat_withIOExceptionThrown() throws Exception {
        // Use reflection to mock CSVPrinter constructor to throw IOException on printRecord
        // Because Mockito.mockConstruction is not available in Mockito 3

        // Create a spy of CSVPrinter that throws IOException on printRecord
        CSVPrinter spyPrinter = mock(CSVPrinter.class);
        doThrow(new IOException("IO error")).when(spyPrinter).printRecord(any());

        // Use reflection to replace CSVPrinter constructor call inside CSVFormat.format
        // We do this by subclassing CSVFormat and overriding format method for the test

        CSVFormat csvFormatMocked = new CSVFormat(csvFormat.getDelimiter(),
                csvFormat.getQuoteCharacter(),
                csvFormat.getQuoteMode(),
                csvFormat.getCommentMarker(),
                csvFormat.getEscapeCharacter(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                null,
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord(),
                csvFormat.getAllowMissingColumnNames(),
                csvFormat.getIgnoreHeaderCase(),
                csvFormat.getTrim(),
                csvFormat.getTrailingDelimiter(),
                csvFormat.getAutoFlush()) {
            @Override
            public String format(final Object... values) {
                StringWriter out = new StringWriter();
                try (CSVPrinter printer = spyPrinter) {
                    printer.printRecord(values);
                    return out.toString().trim();
                } catch (IOException e) {
                    throw new IllegalStateException(e);
                }
            }
        };

        IllegalStateException ex = assertThrows(IllegalStateException.class, () -> {
            csvFormatMocked.format("a", "b");
        });
        assertTrue(ex.getCause() instanceof IOException);
        assertEquals("IO error", ex.getCause().getMessage());
    }
}
